import memcache
from flask import Flask, jsonify
app = Flask(__name__)

@app.route('/api/v1/<int:id>')
def get_user(id):
    mc = memcache.Client(['localhost:11211'], debug=0)

    key = 'user_' + str(id)
    user = mc.get(key)

    if not user:
        user = {
            "id": id,
            "name": "<NAME>",
            "email": "<EMAIL>"
        }

        mc.set(key, user, 3600)

    return jsonify({'user': user})

if __name__ == '__main__':
    app.run()